// Define a function to project fields from a MongoDB collection.
function projectFields(collection, query) {
  // Use the `$project` operator to project only the specified fields.
  const projectedCollection = collection.map(doc => (
    { _id: doc._id, name: doc.name, age: doc.age }
  ));
  return projectedCollection;
}

solutions.python:
class Solution:
  def project_fields(self, collection, query):
    # Use the `$project` operator to project only the specified fields.
    projected_collection = [dict(_id=doc['_id'], name=doc['name'], age=doc['age']) for doc in collection]
    return projected_collection;
